form:Form.form:Scripts:
		var myMENU, myRESULT, myXML, myFAV, myRECENT;

function GetRecent()
{
	if (myRECENT==null)
	{            
		myRECENT=myXML.FirstChild().Next();

		if (GetProxy().StoreService().ExistUserStore("RECIENTES"))
			myRECENT=new NomadXML(GetProxy().StoreService().GetUserStore("RECIENTES"));
	}

	return myRECENT;
}        

function GetFav()
{
	if (myFAV==null)
	{            
		myFAV=myXML.FirstChild();

		if (GetProxy().StoreService().ExistUserStore("FAVORITOS"))
			myFAV=new NomadXML(GetProxy().StoreService().GetUserStore("FAVORITOS"));
	}

	return myFAV;
}        

var ArrIdx;   

function onLoad() 
{        
	var proxy = GetProxy();
	var menuBase=proxy.SQLService().Get(Ctrl("main").getResource("QryApp"),'<DATA name="'+proxy.GetCfgResource("start-form-menu")+'" />');

	myMENU=new nomadDOM(menuBase);

	ArrIdx=new Array();
	for (t=0; t<myMENU.Child.length; t++)
		ArrIdx[t]=myMENU.Child[t].idx;

	Ctrl("Modulos").SetArray(myMENU.Child);
	Ctrl("Modulos").SetCValue("0");





	myRIGHT=new nomadDOM(Ctrl("main").getResource("LeftRoot"));

	myXML   =new NomadXML(Ctrl("main").getResource("LeftRoot"));
	myFAV   =null;
	myRECENT=null;
	myRESULT=myXML.FirstChild().Next().Next();


	Ctrl("menuTopRight").SetArray(myRIGHT.Child);
	Ctrl("menuTopRight").SetCValue("2");

}              

function ChangeModule(OBJ)
{                        
	if (OBJ.values[parseInt(OBJ.GetXValue(),10)].Child.length==0)
	{                                                 
	 	var proxy = GetProxy();
	 	var menuBase=proxy.SQLService().Get(Ctrl("main").getResource("QryModulo"),'<DATA name="'+proxy.GetCfgResource("start-form-menu")+'" idx="'+ArrIdx[parseInt(OBJ.GetXValue(),10)]+'" />');
	 	OBJ.values[parseInt(OBJ.GetXValue(),10)]=new nomadDOM(menuBase);
	}

	Ctrl("Nivel1").SetArray(OBJ.values[parseInt(OBJ.GetXValue(),10)].Child);
	Ctrl("Nivel1").SetCValue("0");
	ChangeNivel1(Ctrl("Nivel1"));
}

function ChangeNivel1(OBJ)
{
	var newArray=new Array();    

	newArray[0]=OBJ.values[parseInt(OBJ.GetXValue(),10)];
	Ctrl("Nivel1_sel").SetArray(newArray);
	Ctrl("Nivel2").SetArray(OBJ.values[parseInt(OBJ.GetXValue(),10)].Child);
}

function ChangeTopRight(OBJ)
{  
	switch(OBJ.values[parseInt(OBJ.GetXValue(),10)].type)
	{
		case "FIND": 
			Ctrl("menuResult").EnabledContextMenu("FAV_ADD",true);
			Ctrl("menuResult").EnabledContextMenu("FAV_UP" ,false);
			Ctrl("menuResult").EnabledContextMenu("FAV_DW" ,false);
			Ctrl("menuResult").EnabledContextMenu("FAV_DEL",false);
			Find();
		break;	           

		case "FAV":
			Ctrl("menuResult").EnabledContextMenu("FAV_ADD",false);
			Ctrl("menuResult").EnabledContextMenu("FAV_UP" ,true);
			Ctrl("menuResult").EnabledContextMenu("FAV_DW" ,true);
			Ctrl("menuResult").EnabledContextMenu("FAV_DEL",true);

			var newArray=new Array();
			newArray[0]=new nomadDOM(GetFav().ToString());	
			Ctrl("menuResult").SetArray(newArray);
		break;	

		case "RECENT":
			Ctrl("menuResult").EnabledContextMenu("FAV_ADD",true);
			Ctrl("menuResult").EnabledContextMenu("FAV_UP" ,false);
			Ctrl("menuResult").EnabledContextMenu("FAV_DW" ,false);
			Ctrl("menuResult").EnabledContextMenu("FAV_DEL",false);

			var newArray=new Array();
			newArray[0]=new nomadDOM(GetRecent().ToString());	
			Ctrl("menuResult").SetArray(newArray);
		break;	
	}
}    

function SaveFav()
{
	//Actualizo la ventana de Recientes
	if (Ctrl("menuTopRight").GetCValue()=="0")                 
	{
			var newArray=new Array();
			newArray[0]=new nomadDOM(GetFav().ToString());	
			Ctrl("menuResult").SetArray(newArray);
	}      

	//Actualizo el Archivo en el Servidor
	GetProxy().StoreService().SetUserStore("FAVORITOS", GetFav().ToString());
}

function AddToFav(OBJ)  
{
	//Agrego el Primer Elemento
	var ITEM=GetFav().AddHeadElement("ITEM");
	ITEM.SetAttr("action",OBJ.LastAction);
	ITEM.SetAttr("label" ,OBJ.LastLabel);

	//Los Elementos Restantes                            
	for (var myCUR=GetFav().FirstChild().Next(); myCUR!=null; myCUR=myCUR.Next())
	{                             
		if (myCUR.GetAttr("action")==OBJ.LastAction)
		{
			GetFav().DeleteChild(myCUR);
			myCUR=GetFav().FirstChild();
		}
	}

	SaveFav();        
}             

function DelFav(OBJ)  
{
	//Lo Elimino de Favorito
	for (var myCUR=GetFav().FirstChild(); myCUR!=null; myCUR=myCUR.Next())
	{                             
		if (myCUR.GetAttr("action")==OBJ.LastAction)
		{
			GetFav().DeleteChild(myCUR);
			myCUR=GetFav().FirstChild();
			break;
		}
	}

	SaveFav();        
}             

function UpFav(OBJ)  
{    
	var Arr=new Array(), pos, Aux;
	for (var myCUR=GetFav().FirstChild(); myCUR!=null; myCUR=myCUR.Next())
	{
		if (myCUR.GetAttr("action")==OBJ.LastAction) pos=Arr.length;
		Arr[Arr.length]=myCUR;
	}

	if (pos<=0) return;
	Aux=Arr[pos]; Arr[pos]=Arr[pos-1]; Arr[pos-1]=Aux;

	//Reconstruyo el XML	
	while (GetFav().FirstChild()!=null) GetFav().DeleteChild(GetFav().FirstChild());
	for (t=0; t<Arr.length; t++)
		GetFav().AddText(Arr[t].ToString());

	SaveFav();
}             

function DownFav(OBJ)  
{
	var Arr=new Array(), pos=-1, Aux;

	for (var myCUR=GetFav().FirstChild(); myCUR!=null; myCUR=myCUR.Next())
	{
		if (myCUR.GetAttr("action")==OBJ.LastAction) pos=Arr.length;
		Arr[Arr.length]=myCUR;
	}

 	if (pos<0) return;
	if (pos>=Arr.length-1) return;
	Aux=Arr[pos]; Arr[pos]=Arr[pos+1]; Arr[pos+1]=Aux;

	//Reconstruyo el XML	
	while (GetFav().FirstChild()!=null) GetFav().DeleteChild(GetFav().FirstChild());
	for (t=0; t<Arr.length; t++)
		GetFav().AddText(Arr[t].ToString());

	SaveFav();
}             

function Find()
{
	var proxy = GetProxy();
	var menuBase;
	var newArray=new Array();

	if (Ctrl("menuTopRight").GetCValue()!="2")
	{                                   
		Ctrl("menuTopRight").SetCValue("2");
	} else
	if (Ctrl("txtBuscar").GetXValue()=="")
	{
		newArray[0]=new nomadDOM(myRESULT.ToString());	
		Ctrl("menuResult").SetArray(newArray);
	} else
	if (Ctrl("txtBuscar").GetXValue()!="")
	{
		var x=new NomadXML("DATA");
		x.SetAttr("name",proxy.GetCfgResource("start-form-menu"));
		x.SetAttr("text",Ctrl("txtBuscar").GetXValue());
		menuBase=proxy.SQLService().Get(Ctrl("main").getResource("QryFind"),x.ToString());
		newArray[0]=new nomadDOM(menuBase);	
		Ctrl("menuResult").SetArray(newArray);
	}
}

function CallFlow(OBJ) 
{                                          

	//Agrego el Primer Elemento
	var ITEM=GetRecent().AddHeadElement("ITEM");
	ITEM.SetAttr("action",OBJ.LastAction);
	ITEM.SetAttr("label" ,OBJ.LastLabel);

	//Los Elementos Restantes                            
	for (var myCUR=GetRecent().FirstChild().Next(); myCUR!=null; myCUR=myCUR.Next())
	{                             
		if (myCUR.GetAttr("action")==OBJ.LastAction)
		{
			GetRecent().DeleteChild(myCUR);
			myCUR=GetRecent().FirstChild();
		}
	}        

	//Limito la Lista a 20 Items
	var Childs=GetRecent().GetChilds();
	for (var t=20; t<Childs.length; t++)
		GetRecent().DeleteChild(Childs[t]);


	//Actualizo la ventana de Recientes
	if (Ctrl("menuTopRight").GetCValue()=="1")                 
	{
			var newArray=new Array();
			newArray[0]=new nomadDOM(GetRecent().ToString());	
			Ctrl("menuResult").SetArray(newArray);
	}      

	//Actualizo el Archivo en el Servidor
	GetProxy().StoreService().SetUserStore("RECIENTES", GetRecent().ToString());


	if (OBJ.LastAction.split(":")[0]=="CUBE")
		getFormInMain('Nomad.Cube.flow', 'initialize', '<DATA cube-name="'+OBJ.LastAction.split(":")[1]+'" />', false);
	else         
	{
		var Params;
		var Actions=OBJ.LastAction.split(":");
		Params=new NomadXML("PARAMS");

		if (Actions.length>2)
		{
			var values=Actions[2].split("&");
			for (var t=0; t<values.length; t++)
			{    
				if (values[t].indexOf("=")>=0)
					Params.SetAttr(	values[t].substr(0,values[t].indexOf("=")), values[t].substr(values[t].indexOf("=")+1));
			}
		}
		getFormInMain(Actions[0], Actions[1], Params.ToString(), false);
	}
}

function Clave()
{
	openNewFlowWait('Nomad.Base.Login.Cuentas.flow',"PASSWORD","",new ObjtectResult(),"");	
}

function ObjtectResult()
{        
	this.processResult= function(xmlin)
	{		
	}
}
